/**
 * @munesoft/objx — get
 * Fast, safe deep property access. lodash.get alternative.
 */
/**
 * Safely retrieve a deeply nested value from an object using a dot/bracket path.
 *
 * @example
 * get({ a: { b: 1 } }, "a.b")       // 1
 * get({ users: ["Alice"] }, "users[0]") // "Alice"
 * get({}, "a.b.c", "default")         // "default"
 */
export declare function get<T = unknown>(obj: unknown, path: string, fallback?: T): T | undefined;
/**
 * Compile a path into a reusable getter function.
 * Eliminates repeated path-parsing overhead in hot loops.
 *
 * @example
 * const getName = compile<string>("user.profile.name");
 * getName(obj); // "Alice"
 */
export declare function compile<T = unknown>(path: string): (obj: unknown, fallback?: T) => T | undefined;
